1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	const LOYALTY_DISCOUNT_RATE = 0.2;
8	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
9	const FOLLOWUP_DISCOUNT_RATE = 0.15;
10	
11	const BASE_PREMIUMS: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const INSURANCE_VALUES: Record<string, number> = {
21	  sword: 1000,
22	  amulet: 600,
23	  staff: 800,
24	  potion: 400,
25	  rune: 250,
26	  moonstone: 250,
27	};
28	
29	const DEDUCTIBLE = 100;
30	const CAP_MULTIPLIER = 2;
31	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
32	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
33	
34	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
35	type QuoteStep = { op: "quote"; items: Item[] };
36	type Damage = { itemType: string; amount: number };
37	type Incident = { cause: string; damages: Damage[] };
38	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
39	type Step = QuoteStep | ClaimStep;
40	type Customer = { yearsWithMHPCO: number };
41	type Scenario = { customer: Customer; steps: Step[] };
42	
43	const sum = (numbers: number[]): number =>
44	  numbers.reduce((total, n) => total + n, 0);
45	
46	const policyInsuranceSum = (items: Item[]): number =>
47	  sum(items.map((item) => INSURANCE_VALUES[item.type]));
48	
49	const isHighEnchantmentForReimbursement = (item: Item): boolean =>
50	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD;
51	
52	const effectiveDamage = (item: Item, damageAmount: number): number =>
53	  isHighEnchantmentForReimbursement(item)
54	    ? damageAmount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
55	    : damageAmount;
56	
57	const claimResult = (policyItems: Item[], step: ClaimStep) => {
58	  const cap = CAP_MULTIPLIER * policyInsuranceSum(policyItems);
59	  const damage = step.incident.damages[0];
60	  const damagedItem = policyItems.find((item) => item.type === damage.itemType)!;
61	  const payout = effectiveDamage(damagedItem, damage.amount) - DEDUCTIBLE;
62	  return { payout, remainingCap: cap - payout };
63	};
64	
65	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
66	
67	const isBlockOfThreeAlike = (items: Item[]): boolean =>
68	  items.length === 3 && items.every((item) => item.type === items[0].type);
69	
70	const groupByType = (items: Item[]): Item[][] => {
71	  const groups: Record<string, Item[]> = {};
72	  for (const item of items) {
73	    (groups[item.type] ||= []).push(item);
74	  }
75	  return Object.values(groups);
76	};
77	
78	const groupBasePremium = (group: Item[]): number =>
79	  isBlockOfThreeAlike(group)
80	    ? BLOCK_OF_THREE_BASE_PREMIUM
81	    : sum(group.map(itemBasePremium));
82	
83	const itemsBasePremium = (items: Item[]): number =>
84	  sum(groupByType(items).map(groupBasePremium));
85	
86	const rateIfApplies = (amount: number, applies: boolean, rate: number): number =>
87	  applies ? amount * rate : 0;
88	
89	const cursedSurcharge = (item: Item): number =>
90	  rateIfApplies(itemBasePremium(item), item.cursed === true, CURSED_SURCHARGE_RATE);
91	
92	const highEnchantmentSurcharge = (item: Item): number =>
93	  rateIfApplies(
94	    itemBasePremium(item),
95	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
96	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
97	  );
98	
99	const itemSurchargesTotal = (items: Item[]): number =>
100	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
101	
102	const firstInsuranceSurcharge = (basePremium: number): number =>
103	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
104	
105	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
106	  rateIfApplies(
107	    basePremium,
108	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS,
109	    LOYALTY_DISCOUNT_RATE,
110	  );
111	
112	const followupDiscount = (basePremium: number, quoteIndex: number): number =>
113	  rateIfApplies(basePremium, quoteIndex >= 1, FOLLOWUP_DISCOUNT_RATE);
114	
115	const quotePremiumFor = (items: Item[], customer: Customer, quoteIndex: number): number => {
116	  const policyBase = itemsBasePremium(items);
117	  return Math.ceil(
118	    policyBase +
119	      itemSurchargesTotal(items) +
120	      firstInsuranceSurcharge(policyBase) -
121	      loyaltyDiscount(policyBase, customer) -
122	      followupDiscount(policyBase, quoteIndex) +
123	      PROCESSING_FEE,
124	  );
125	};
126	
127	export const runScenario = (input: Scenario): unknown => {
128	  const results: unknown[] = [];
129	  const quotedPolicies: Item[][] = [];
130	  for (const step of input.steps) {
131	    if (step.op === "quote") {
132	      const premium = quotePremiumFor(step.items, input.customer, quotedPolicies.length);
133	      results.push({ premium });
134	      quotedPolicies.push(step.items);
135	    } else {
136	      results.push(claimResult(quotedPolicies[step.policy], step));
137	    }
138	  }
139	  return { results };
140	};
